function mapPriority(intakePriority) {
  if (!intakePriority) return "normal";
  const priority = intakePriority.toLowerCase();
  switch (priority) {
    case "urgent":
      return "urgent";
    case "high":
      return "high";
    case "medium":
      return "normal";
    case "low":
      return "low";
    default:
      return "normal";
  }
}

