  app2.get("/api/custom-field-folders", requireAuth(), requirePermission("settings", "canView"), async (req, res) => {
    try {
      const { search } = req.query;
      let folders;
      if (search && typeof search === "string") {
        folders = await db.select({
          id: customFieldFolders.id,
          name: customFieldFolders.name,
          order: customFieldFolders.order,
          isDefault: customFieldFolders.isDefault,
          canReorder: customFieldFolders.canReorder,
          createdAt: customFieldFolders.createdAt,
          fieldCount: sql3`(SELECT COUNT(*) FROM ${customFields} WHERE ${customFields.folderId} = ${customFieldFolders.id})`
        }).from(customFieldFolders).where(like2(customFieldFolders.name, `%${search}%`)).orderBy(asc2(customFieldFolders.order));
      } else {
        folders = await db.select({
          id: customFieldFolders.id,
          name: customFieldFolders.name,
          order: customFieldFolders.order,
          isDefault: customFieldFolders.isDefault,
          canReorder: customFieldFolders.canReorder,
          createdAt: customFieldFolders.createdAt,
          fieldCount: sql3`(SELECT COUNT(*) FROM ${customFields} WHERE ${customFields.folderId} = ${customFieldFolders.id})`
        }).from(customFieldFolders).orderBy(asc2(customFieldFolders.order));
      }
      res.json(folders);
    } catch (error) {
      console.error("Error fetching custom field folders:", error);
      res.status(500).json({ message: "Failed to fetch custom field folders" });
    }
  });
  app2.post("/api/custom-field-folders", requireAuth(), requirePermission("settings", "canManage"), async (req, res) => {
    try {
      const { name } = req.body;
      if (!name || name.trim() === "") {
        return res.status(400).json({ message: "Folder name is required" });
      }
      const maxOrderResult = await db.select({ maxOrder: sql3`COALESCE(MAX(${customFieldFolders.order}), 0)` }).from(customFieldFolders);
      const nextOrder = (maxOrderResult[0]?.maxOrder || 0) + 1;
      const newFolder = await db.insert(customFieldFolders).values({
        name: name.trim(),
        order: nextOrder,
        isDefault: false,
        canReorder: true
      }).returning();
      res.status(201).json(newFolder[0]);
    } catch (error) {
      console.error("Error creating custom field folder:", error);
      res.status(500).json({ message: "Failed to create custom field folder" });
    }
  });
  app2.put("/api/custom-field-folders/reorder", requireAuth(), requirePermission("settings", "canManage"), async (req, res) => {
    try {
      const { folderIds } = req.body;
      if (!Array.isArray(folderIds)) {
        return res.status(400).json({ message: "folderIds must be an array" });
      }
      for (let i = 0; i < folderIds.length; i++) {
        const folderId = folderIds[i];
        const newOrder = i + 1;
        await db.update(customFieldFolders).set({ order: newOrder }).where(eq8(customFieldFolders.id, folderId));
      }
      res.json({ message: "Folder order updated successfully" });
    } catch (error) {
      console.error("Error reordering custom field folders:", error);
      res.status(500).json({ message: "Failed to reorder folders" });
    }
  });
