  async function syncLeadAppointmentToSalesActivity(appointment) {
    try {
      const statusToOutcomeMap = {
        "confirmed": "scheduled",
        "showed": "completed",
        "no_show": "no_show",
        "cancelled": "cancelled",
        "pending": "scheduled"
      };
      const validActivityTypes = ["appointment", "pitch", "demo", "follow-up"];
      let activityType = "appointment";
      if (appointment.activityType) {
        const normalized = appointment.activityType.toLowerCase().trim();
        if (validActivityTypes.includes(normalized)) {
          activityType = normalized;
        } else {
          console.warn(`Invalid activity type "${appointment.activityType}" - using default "appointment"`);
        }
      }
      const outcome = statusToOutcomeMap[appointment.status] || "scheduled";
      const completedAt = appointment.status === "showed" ? /* @__PURE__ */ new Date() : null;
      const existing = await db.select().from(salesActivities).where(sql3`${salesActivities.notes} LIKE '%[appointment_id:' || ${appointment.id} || ']%'`).limit(1);
      const salesActivityData = {
        leadId: appointment.leadId,
        type: activityType,
        outcome,
        notes: `${appointment.title || ""}
${appointment.description || ""}
[appointment_id:${appointment.id}]`,
        assignedTo: appointment.assignedTo,
        scheduledAt: appointment.startTime,
        completedAt
      };
      if (existing && existing.length > 0) {
        await db.update(salesActivities).set(salesActivityData).where(eq8(salesActivities.id, existing[0].id));
        console.log(`\u2705 Updated sales activity ${existing[0].id} for appointment ${appointment.id}`);
      } else {
        await db.insert(salesActivities).values(salesActivityData);
        console.log(`\u2705 Created sales activity for appointment ${appointment.id}`);
      }
    } catch (error) {
      console.error("Error syncing lead appointment to sales activity:", error);
    }
  }
